export async function ensureSchema(client) {
  if (schemaReady) return;

  // Check if accounts table already has the doc column (JSONB-style)
  const check = await client.query(
    `SELECT column_name FROM information_schema.columns
     WHERE table_schema = current_schema() AND table_name = 'accounts' AND column_name = 'doc'`
  );

  if (check.rows.length === 0) {
    // Drop all tables and recreate in JSONB style
    const tablesToDrop = [
      'consent_records', 'data_processing_agreements', 'audit_trails',
      'regulatory_flags', 'compliance_reviews', 'sla_policies',
      'product_inventory', 'product_reviews', 'product_pricing',
      'product_categories', 'products',
      'support_assignments', 'case_escalations', 'case_comments', 'support_cases',
      'delivery_confirmations', 'shipment_tracking', 'shipment_items', 'shipments',
      'order_returns', 'order_fulfillments', 'order_status_history',
      'order_approvals', 'order_line_items', 'orders',
      'billing_cycles', 'tax_records', 'credit_notes', 'payment_methods',
      'payments', 'invoice_line_items', 'invoices',
      'account_contracts', 'account_health_scores', 'account_billing',
      'account_team', 'account_preferences', 'account_settings',
      'account_details', 'accounts',
    ];
    for (const t of tablesToDrop) {
      await client.query(`DROP TABLE IF EXISTS ${t} CASCADE`);
    }
  }

  for (const sql of JSONB_TABLES) {
    await client.query(sql);
  }
  for (const sql of JSONB_INDEXES) {
    try { await client.query(sql); } catch { /* ignore */ }
  }

  schemaReady = true;
}
